arguments.command:
cat > /tmp/search_pattern.py << 'EOF'
import os
import re

# Patterns to search for
convergence_warning_files = set()
verbose_param_files = set()
check_is_fitted_files = set()

base_path = "/workspace/scikit-learn/sklearn"

for root, dirs, files in os.walk(base_path):
    # Skip tests directories
    if "tests" in root:
        continue

    for file in files:
        if not file.endswith(".py"):
            continue

        filepath = os.path.join(root, file)
        try:
            with open(filepath, 'r', encoding='utf-8', errors='ignore') as f:
                content = f.read()

                if "ConvergenceWarning" in content:
                    convergence_warning_files.add(filepath)

                if re.search(r'\bverbose\s*[=,)]', content):
                    verbose_param_files.add(filepath)

                if "check_is_fitted" in content:
                    check_is_fitted_files.add(filepath)
        except:
            pass

print("=== Files with ConvergenceWarning ===")
for f in sorted(convergence_warning_files):
    print(f.replace("/workspace/scikit-learn/", ""))

print("\n=== Files with verbose parameter ===")  
for f in sorted(verbose_param_files)[:30]:
    print(f.replace("/workspace/scikit-learn/", ""))

print("\n=== Files with check_is_fitted ===")
for f in sorted(check_is_fitted_files)[:30]:
    print(f.replace("/workspace/scikit-learn/", ""))
EOF
python /tmp/search_pattern.py

